async (page) => {
  // Try to find and click death screen respawn button
  const respawnBtn = await page.evaluate(() => {
    // Look for death/respawn buttons
    const buttons = ['#death', '#respawn', '.death-button', '#continue', '#respawn-button'];
    for (const sel of buttons) {
      const el = document.querySelector(sel);
      if (el) { el.click(); return 'clicked: ' + sel; }
    }
    // Check all visible buttons
    const allBtns = Array.from(document.querySelectorAll('button, [id*="death"], [id*="respawn"]'));
    const visible = allBtns.filter(b => {
      const s = window.getComputedStyle(b);
      return s.display !== 'none' && s.visibility !== 'hidden';
    });
    return 'no respawn btn, visible buttons: ' + visible.map(b => b.id || b.className).join(', ');
  });
  return respawnBtn;
}

