async (page) => {
  // Set attack style to Hack (index 0)
  await page.evaluate(() => {
    if (window.game && window.game.player) window.game.player.setAttackStyle(0);
  });

  // Close welcome dialog if present
  await page.evaluate(() => {
    const btn = document.getElementById('close-welcome');
    if (btn) btn.click();
  });

  // Warp to Mudwich
  await page.evaluate(() => {
    window.game.menu.warp.show();
    setTimeout(() => document.getElementById('warp0').click(), 500);
  });
  await page.waitForTimeout(3000);

  const state = await page.evaluate(() => JSON.stringify(window.__latestGameState));
  const parsed = JSON.parse(state);

  // Check actual skills  
  const skills = await page.evaluate(() => {
    const p = window.game.player;
    if (!p || !p.skills) return {};
    const result = {};
    Object.entries(p.skills).forEach(([k, v]) => {
      if (v.experience > 0) result[v.name] = { level: v.level, xp: v.experience, next: v.nextExperience };
    });
    return result;
  });

  return JSON.stringify({ pos: parsed.player_position, hp: parsed.player_stats, isDead: parsed.ui_state.is_dead, skills });
}

